CREATE SCHEMA IF NOT EXISTS sarf;

-- =============================================
-- USERS TABLE
-- account_number is the PRIMARY KEY (6 digits, generated by function below)
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.users (
    account_number         VARCHAR(6)   PRIMARY KEY,
    first_name             VARCHAR(100) NOT NULL,
    last_name              VARCHAR(100) NOT NULL,
    date_of_birth          DATE         NOT NULL,
    gender                 VARCHAR(10)  NOT NULL CHECK (gender IN ('MALE', 'FEMALE', 'OTHER')),
    email                  VARCHAR(255),
    country_code           VARCHAR(5),
    phone_number           VARCHAR(15),
    password_hash          VARCHAR(255),
    google_id              VARCHAR(255),
    registration_type      VARCHAR(10)  NOT NULL CHECK (registration_type IN ('PHONE', 'GOOGLE')),
    registration_date_time TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at             TIMESTAMP    NOT NULL DEFAULT NOW(),
    UNIQUE (country_code, phone_number),
    UNIQUE (email),
    UNIQUE (google_id)
);

-- =============================================
-- OTP RECORDS TABLE
-- Stores only the OTP code for a given phone.
-- No registration data that arrives later in /register.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.otp_records (
    id                     BIGSERIAL   PRIMARY KEY,
    country_code           VARCHAR(5)  NOT NULL,
    phone_number           VARCHAR(15) NOT NULL,
    otp_code               VARCHAR(64) NOT NULL,
    expires_at             TIMESTAMP   NOT NULL,
    used                   BOOLEAN     NOT NULL DEFAULT FALSE,
    registration_date_time TIMESTAMP   NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_otp_phone
    ON sarf.otp_records (country_code, phone_number, used, expires_at);

-- =============================================
-- REGISTRATION SESSIONS TABLE
-- Short-lived token issued after OTP is confirmed.
-- Required to call /registration/submit.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.registration_sessions (
    id            BIGSERIAL   PRIMARY KEY,
    session_token VARCHAR(64) NOT NULL UNIQUE,
    country_code  VARCHAR(5)  NOT NULL,
    phone_number  VARCHAR(15) NOT NULL,
    expires_at    TIMESTAMP   NOT NULL,
    used          BOOLEAN     NOT NULL DEFAULT FALSE,
    created_at    TIMESTAMP   NOT NULL DEFAULT NOW()
);

-- =============================================
-- LOGIN AUDIT TABLE
-- Records every login attempt (success and failure).
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.login_audit (
    id                BIGSERIAL   PRIMARY KEY,
    account_number    VARCHAR(6)  REFERENCES sarf.users(account_number),
    device_id         VARCHAR(255),
    response_code     VARCHAR(10) NOT NULL,
    registration_type VARCHAR(10),
    login_date_time   TIMESTAMP   NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_login_audit_device
    ON sarf.login_audit (device_id, login_date_time);

CREATE INDEX IF NOT EXISTS idx_login_audit_account
    ON sarf.login_audit (account_number, login_date_time);

-- =============================================
-- USER DEVICES TABLE
-- Stores known devices per account.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.user_devices (
    id             BIGSERIAL    PRIMARY KEY,
    account_number VARCHAR(6)   NOT NULL REFERENCES sarf.users(account_number),
    device_id      VARCHAR(64)  NOT NULL,
    device_name    VARCHAR(150),
    fcm_token      VARCHAR(512),
    first_seen_at  TIMESTAMP    NOT NULL DEFAULT NOW(),
    last_seen_at   TIMESTAMP    NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_user_devices_account_device UNIQUE (account_number, device_id)
);

CREATE INDEX IF NOT EXISTS idx_user_devices_account
    ON sarf.user_devices (account_number);

-- =============================================
-- CURRENCIES TABLE
-- Master list of supported fiat and metals.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.currencies (
    code          VARCHAR(10)  PRIMARY KEY,
    name_en       VARCHAR(100) NOT NULL,
    name_ar       VARCHAR(100) NOT NULL,
    symbol        VARCHAR(20),
    country_code  VARCHAR(5),
    active        BOOLEAN      NOT NULL DEFAULT TRUE,
    display_order INTEGER      NOT NULL DEFAULT 0,
    is_metal      BOOLEAN      NOT NULL DEFAULT FALSE,
    created_at    TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMP    NOT NULL DEFAULT NOW()
);

