-- =============================================
-- PRICE HISTORY TABLE
-- Historical rates snapshots.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.price_history (
    id            BIGSERIAL      PRIMARY KEY,
    source        VARCHAR(50)    NOT NULL,
    currency_code VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    price         NUMERIC(18, 6) NOT NULL,
    tran_date     DATE           NOT NULL DEFAULT CURRENT_DATE,
    tran_time     TIME           NOT NULL DEFAULT CURRENT_TIME
);

CREATE INDEX IF NOT EXISTS idx_price_history_source
    ON sarf.price_history (source);

CREATE INDEX IF NOT EXISTS idx_price_history_currency
    ON sarf.price_history (currency_code);

CREATE INDEX IF NOT EXISTS idx_price_history_date
    ON sarf.price_history (tran_date);

CREATE INDEX IF NOT EXISTS idx_price_history_source_currency_date_time
    ON sarf.price_history (source, currency_code, tran_date, tran_time);

