-- =============================================
-- MERCHANT RECEIVING ACCOUNTS
-- Account details shown to the user in internal transfer flows.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.merchant_accounts (
    id                 BIGSERIAL    PRIMARY KEY,
    merchant_id        BIGINT       NOT NULL REFERENCES sarf.merchants(id),
    transfer_method_id BIGINT       NOT NULL REFERENCES sarf.transfer_methods(id),
    account_name       VARCHAR(150) NOT NULL,
    account_number     VARCHAR(100),
    iban               VARCHAR(100),
    wallet_number      VARCHAR(50),
    bank_name          VARCHAR(100),
    instructions_en    VARCHAR(500),
    instructions_ar    VARCHAR(500),
    active             BOOLEAN      NOT NULL DEFAULT TRUE,
    created_at         TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at         TIMESTAMP    NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_merchant_method_account UNIQUE (merchant_id, transfer_method_id)
);

CREATE INDEX IF NOT EXISTS idx_merchant_accounts_merchant_method
    ON sarf.merchant_accounts (merchant_id, transfer_method_id, active);

INSERT INTO sarf.merchant_accounts (
    merchant_id, transfer_method_id, account_name, account_number, iban,
    wallet_number, bank_name, instructions_en, instructions_ar, active
)
SELECT
    m.id,
    tm.id,
    CASE m.code
        WHEN 'merchant_rahma' THEN 'Rahma Sarf'
        WHEN 'merchant_sondos' THEN 'Sondos Exchange'
        WHEN 'merchant_moez' THEN 'Moez Transfer'
    END,
    CASE tm.code
        WHEN 'bankak' THEN CASE m.code WHEN 'merchant_rahma' THEN '0912345678' WHEN 'merchant_sondos' THEN '0922233344' ELSE '0933300044' END
        WHEN 'faisal_bank' THEN CASE m.code WHEN 'merchant_rahma' THEN '220011445566' WHEN 'merchant_sondos' THEN '220011998877' ELSE '110022334455' END
        WHEN 'onb_bank' THEN CASE m.code WHEN 'merchant_rahma' THEN '998877665544' WHEN 'merchant_sondos' THEN '776655443322' ELSE '554433221100' END
        ELSE NULL
    END,
    NULL,
    CASE tm.code
        WHEN 'mycash_wallet' THEN CASE m.code WHEN 'merchant_rahma' THEN '0998877665' WHEN 'merchant_sondos' THEN '0990011223' ELSE '0994455667' END
        WHEN 'bravo' THEN CASE m.code WHEN 'merchant_rahma' THEN '0998877665' WHEN 'merchant_sondos' THEN '0990011223' ELSE '0994455667' END
        ELSE NULL
    END,
    CASE tm.category
        WHEN 'BANK' THEN tm.name_en
        ELSE tm.name_en
    END,
    'Transfer exactly the quoted amount and upload your receipt.',
    'حوّل المبلغ المطابق للعرض ثم ارفع الإيصال.',
    TRUE
FROM sarf.merchants m
JOIN sarf.transfer_methods tm
  ON tm.code IN ('bankak', 'faisal_bank', 'onb_bank', 'mycash_wallet', 'bravo')
ON CONFLICT (merchant_id, transfer_method_id) DO UPDATE SET
    account_name = EXCLUDED.account_name,
    account_number = EXCLUDED.account_number,
    wallet_number = EXCLUDED.wallet_number,
    bank_name = EXCLUDED.bank_name,
    instructions_en = EXCLUDED.instructions_en,
    instructions_ar = EXCLUDED.instructions_ar,
    active = EXCLUDED.active,
    updated_at = NOW();

-- =============================================
-- INTERNAL TRANSFER ROUTES
-- Defines allowed source -> target pairs for local transfer.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.internal_transfer_routes (
    id                 BIGSERIAL      PRIMARY KEY,
    source_method_id   BIGINT         NOT NULL REFERENCES sarf.transfer_methods(id),
    target_method_id   BIGINT         NOT NULL REFERENCES sarf.transfer_methods(id),
    rate               NUMERIC(18, 6) NOT NULL DEFAULT 1.0,
    min_amount         NUMERIC(18, 2),
    max_amount         NUMERIC(18, 2),
    active             BOOLEAN        NOT NULL DEFAULT TRUE,
    created_at         TIMESTAMP      NOT NULL DEFAULT NOW(),
    updated_at         TIMESTAMP      NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_internal_transfer_route UNIQUE (source_method_id, target_method_id),
    CONSTRAINT chk_internal_route_diff CHECK (source_method_id <> target_method_id)
);

CREATE INDEX IF NOT EXISTS idx_internal_transfer_routes_active
    ON sarf.internal_transfer_routes (source_method_id, active);

INSERT INTO sarf.internal_transfer_routes (
    source_method_id, target_method_id, rate, min_amount, max_amount, active
)
SELECT
    src.id,
    dst.id,
    1.0,
    100.00,
    10000000.00,
    TRUE
FROM sarf.transfer_methods src
JOIN sarf.transfer_methods dst
  ON (src.code, dst.code) IN (
      ('bankak', 'faisal_bank'),
      ('bankak', 'onb_bank'),
      ('faisal_bank', 'bankak'),
      ('faisal_bank', 'mycash_wallet'),
      ('faisal_bank', 'bravo'),
      ('onb_bank', 'bankak'),
      ('mycash_wallet', 'onb_bank'),
      ('bravo', 'onb_bank')
  )
ON CONFLICT (source_method_id, target_method_id) DO UPDATE SET
    rate = EXCLUDED.rate,
    min_amount = EXCLUDED.min_amount,
    max_amount = EXCLUDED.max_amount,
    active = EXCLUDED.active,
    updated_at = NOW();

-- =============================================
-- MERCHANT ROUTE SUPPORT
-- Which merchant can fulfill which internal route.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.merchant_route_support (
    id                 BIGSERIAL   PRIMARY KEY,
    merchant_id        BIGINT      NOT NULL REFERENCES sarf.merchants(id),
    route_id           BIGINT      NOT NULL REFERENCES sarf.internal_transfer_routes(id),
    min_amount         NUMERIC(18, 2),
    max_amount         NUMERIC(18, 2),
    active             BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at         TIMESTAMP   NOT NULL DEFAULT NOW(),
    updated_at         TIMESTAMP   NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_merchant_route_support UNIQUE (merchant_id, route_id)
);

CREATE INDEX IF NOT EXISTS idx_merchant_route_support_active
    ON sarf.merchant_route_support (route_id, active);

INSERT INTO sarf.merchant_route_support (
    merchant_id, route_id, min_amount, max_amount, active
)
SELECT
    m.id,
    r.id,
    100.00,
    10000000.00,
    TRUE
FROM sarf.merchants m
CROSS JOIN sarf.internal_transfer_routes r
ON CONFLICT (merchant_id, route_id) DO UPDATE SET
    min_amount = EXCLUDED.min_amount,
    max_amount = EXCLUDED.max_amount,
    active = EXCLUDED.active,
    updated_at = NOW();

-- =============================================
-- MERCHANT FEE CONFIGS
-- Configurable globally or per internal route.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.merchant_fee_configs (
    id           BIGSERIAL      PRIMARY KEY,
    merchant_id  BIGINT         NOT NULL REFERENCES sarf.merchants(id),
    service_code VARCHAR(50)    NOT NULL REFERENCES sarf.transfer_services(code),
    route_id     BIGINT         REFERENCES sarf.internal_transfer_routes(id),
    fee_type     VARCHAR(20)    NOT NULL CHECK (fee_type IN ('FIXED', 'PERCENTAGE')),
    fee_value    NUMERIC(18, 4) NOT NULL,
    min_fee      NUMERIC(18, 2),
    max_fee      NUMERIC(18, 2),
    active       BOOLEAN        NOT NULL DEFAULT TRUE,
    created_at   TIMESTAMP      NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMP      NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_merchant_fee_configs_lookup
    ON sarf.merchant_fee_configs (merchant_id, service_code, route_id, active);

CREATE UNIQUE INDEX IF NOT EXISTS uq_merchant_fee_config_route
    ON sarf.merchant_fee_configs (merchant_id, service_code, route_id)
    WHERE route_id IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_merchant_fee_config_global
    ON sarf.merchant_fee_configs (merchant_id, service_code)
    WHERE route_id IS NULL;

INSERT INTO sarf.merchant_fee_configs (
    merchant_id, service_code, route_id, fee_type, fee_value, min_fee, max_fee, active
)
SELECT
    m.id,
    'local_transfer',
    NULL,
    'PERCENTAGE',
    CASE m.code
        WHEN 'merchant_rahma' THEN 1.50
        WHEN 'merchant_sondos' THEN 1.20
        WHEN 'merchant_moez' THEN 1.80
    END,
    NULL,
    NULL,
    TRUE
FROM sarf.merchants m
WHERE NOT EXISTS (
    SELECT 1
    FROM sarf.merchant_fee_configs fc
    WHERE fc.merchant_id = m.id
      AND fc.service_code = 'local_transfer'
      AND fc.route_id IS NULL
);

-- =============================================
-- EXCHANGE HOUSES
-- Partner payout desks for international transfer.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.exchange_houses (
    id            BIGSERIAL    PRIMARY KEY,
