    notes_en = EXCLUDED.notes_en,
    notes_ar = EXCLUDED.notes_ar,
    active = EXCLUDED.active,
    display_order = EXCLUDED.display_order,
    updated_at = NOW();

-- =============================================
-- TRANSFER PROVIDERS
-- External remittance providers.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.transfer_providers (
    id            BIGSERIAL    PRIMARY KEY,
    code          VARCHAR(50)  NOT NULL UNIQUE,
    name_en       VARCHAR(100) NOT NULL,
    name_ar       VARCHAR(100) NOT NULL,
    logo_url      VARCHAR(500),
    notes_en      VARCHAR(500),
    notes_ar      VARCHAR(500),
    active        BOOLEAN      NOT NULL DEFAULT TRUE,
    display_order INTEGER      NOT NULL DEFAULT 0,
    created_at    TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMP    NOT NULL DEFAULT NOW()
);

INSERT INTO sarf.transfer_providers (
    code, name_en, name_ar, logo_url, notes_en, notes_ar, active, display_order
) VALUES
    ('wistron_transfer', 'Wistron Transfer', 'ويسترون ترانسفير',
     'https://play-lh.googleusercontent.com/WEI7',
     'Wistron reference number is required for all transfers.',
     'رقم مرجع ويسترون مطلوب لجميع الحوالات.',
     TRUE, 1),
    ('moneygram', 'MoneyGram', 'موني جرام',
     'https://play-lh.googleusercontent.com/uoo6Vd556jKBapSQyJUcZHxlDANJkH9ddMleB-7cKBUMmAA5iZ5FB6-V7st0putVXHReopMAxtzg8rw-8266CXo=w240-h480-rw',
     'No reference number is needed for MoneyGram transfers.',
     'لا يلزم رقم مرجع لحوالات موني جرام.',
     TRUE, 2)
ON CONFLICT (code) DO UPDATE SET
    name_en = EXCLUDED.name_en,
    name_ar = EXCLUDED.name_ar,
    logo_url = EXCLUDED.logo_url,
    notes_en = EXCLUDED.notes_en,
    notes_ar = EXCLUDED.notes_ar,
    active = EXCLUDED.active,
    display_order = EXCLUDED.display_order,
    updated_at = NOW();

-- =============================================
-- EXCHANGE / PROVIDER SUPPORT
-- Which providers are supported by each exchange house.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.exchange_provider_support (
    id                BIGSERIAL  PRIMARY KEY,
    exchange_house_id BIGINT     NOT NULL REFERENCES sarf.exchange_houses(id),
    provider_id       BIGINT     NOT NULL REFERENCES sarf.transfer_providers(id),
    active            BOOLEAN    NOT NULL DEFAULT TRUE,
    display_order     INTEGER    NOT NULL DEFAULT 0,
    created_at        TIMESTAMP  NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMP  NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_exchange_provider_support UNIQUE (exchange_house_id, provider_id)
);

INSERT INTO sarf.exchange_provider_support (
    exchange_house_id, provider_id, active, display_order
)
SELECT
    eh.id,
    tp.id,
    TRUE,
    tp.display_order
FROM sarf.exchange_houses eh
JOIN sarf.transfer_providers tp
  ON tp.code IN ('wistron_transfer', 'moneygram')
WHERE eh.code = 'mig'
ON CONFLICT (exchange_house_id, provider_id) DO UPDATE SET
    active = EXCLUDED.active,
    display_order = EXCLUDED.display_order,
    updated_at = NOW();

-- =============================================
-- PROVIDER REFERENCE RULES
-- Reference input is provider-specific and can be required or optional.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.provider_reference_rules (
    id                         BIGSERIAL    PRIMARY KEY,
    exchange_provider_id       BIGINT       NOT NULL REFERENCES sarf.exchange_provider_support(id),
    required                   BOOLEAN      NOT NULL DEFAULT TRUE,
    field_label_en             VARCHAR(100) NOT NULL DEFAULT 'Reference number',
    field_label_ar             VARCHAR(100) NOT NULL DEFAULT 'رقم المرجع',
    validation_regex           VARCHAR(255),
    help_text_en               VARCHAR(255),
    help_text_ar               VARCHAR(255),
    created_at                 TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at                 TIMESTAMP    NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_provider_reference_rule UNIQUE (exchange_provider_id)
);

INSERT INTO sarf.provider_reference_rules (
    exchange_provider_id, required, field_label_en, field_label_ar,
    validation_regex, help_text_en, help_text_ar
)
SELECT
    eps.id,
    CASE tp.code WHEN 'wistron_transfer' THEN TRUE ELSE FALSE END,
    'Reference number',
    'رقم المرجع',
    NULL,
    CASE tp.code
        WHEN 'wistron_transfer' THEN 'Enter the transfer reference from Wistron.'
        ELSE 'Reference is optional for this provider.'
    END,
    CASE tp.code
        WHEN 'wistron_transfer' THEN 'أدخل رقم مرجع التحويل من ويسترون.'
        ELSE 'المرجع اختياري لهذا المزود.'
    END
FROM sarf.exchange_provider_support eps
JOIN sarf.transfer_providers tp ON tp.id = eps.provider_id
JOIN sarf.exchange_houses eh ON eh.id = eps.exchange_house_id
WHERE eh.code = 'mig'
ON CONFLICT (exchange_provider_id) DO UPDATE SET
    required = EXCLUDED.required,
    field_label_en = EXCLUDED.field_label_en,
    field_label_ar = EXCLUDED.field_label_ar,
    validation_regex = EXCLUDED.validation_regex,
    help_text_en = EXCLUDED.help_text_en,
    help_text_ar = EXCLUDED.help_text_ar,
    updated_at = NOW();

-- =============================================
-- EXCHANGE PROVIDER RATES
-- Provider-specific rates by exchange and source currency.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.exchange_provider_rates (
    id                    BIGSERIAL      PRIMARY KEY,
    exchange_provider_id  BIGINT         NOT NULL REFERENCES sarf.exchange_provider_support(id),
    send_currency_code    VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    receive_currency_code VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    rate                  NUMERIC(18, 6) NOT NULL,
    fee_type              VARCHAR(20)    CHECK (fee_type IN ('FIXED', 'PERCENTAGE')),
    fee_value             NUMERIC(18, 4),
    min_amount            NUMERIC(18, 2),
    max_amount            NUMERIC(18, 2),
    note_en               VARCHAR(255),
    note_ar               VARCHAR(255),
    active                BOOLEAN        NOT NULL DEFAULT TRUE,
    created_at            TIMESTAMP      NOT NULL DEFAULT NOW(),
    updated_at            TIMESTAMP      NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_exchange_provider_rate UNIQUE (exchange_provider_id, send_currency_code, receive_currency_code)
);

INSERT INTO sarf.exchange_provider_rates (
    exchange_provider_id, send_currency_code, receive_currency_code, rate,
    fee_type, fee_value, min_amount, max_amount, note_en, note_ar, active
)
SELECT
    eps.id,
    rate_data.send_currency_code,
    'SDG',
    rate_data.rate,
    NULL,
    NULL,
    1.00,
    1000000.00,
    rate_data.note_en,
    rate_data.note_ar,
    TRUE
FROM sarf.exchange_provider_support eps
JOIN sarf.transfer_providers tp ON tp.id = eps.provider_id
JOIN sarf.exchange_houses eh ON eh.id = eps.exchange_house_id
JOIN (
    VALUES
        ('wistron_transfer', 'USD', 2488.00::NUMERIC, NULL::VARCHAR, NULL::VARCHAR),
        ('wistron_transfer', 'SAR', 663.50::NUMERIC, 'Rates are updated daily at 12 PM UTC.', 'يتم تحديث الأسعار يومياً الساعة 12 ظهراً بتوقيت UTC.'),
        ('moneygram', 'USD', 2480.00::NUMERIC, NULL::VARCHAR, NULL::VARCHAR)
) AS rate_data(provider_code, send_currency_code, rate, note_en, note_ar)
  ON rate_data.provider_code = tp.code
WHERE eh.code = 'mig'
ON CONFLICT (exchange_provider_id, send_currency_code, receive_currency_code) DO UPDATE SET
    rate = EXCLUDED.rate,
    fee_type = EXCLUDED.fee_type,
    fee_value = EXCLUDED.fee_value,
    min_amount = EXCLUDED.min_amount,
    max_amount = EXCLUDED.max_amount,
    note_en = EXCLUDED.note_en,
    note_ar = EXCLUDED.note_ar,
    active = EXCLUDED.active,
    updated_at = NOW();

-- =============================================
-- EXCHANGE RECEIVE METHODS
-- Which local methods are available for payout for each exchange house.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.exchange_receive_methods (
    id                          BIGSERIAL    PRIMARY KEY,
    exchange_house_id           BIGINT       NOT NULL REFERENCES sarf.exchange_houses(id),
    transfer_method_id          BIGINT       NOT NULL REFERENCES sarf.transfer_methods(id),
    note_en                     VARCHAR(255),
    note_ar                     VARCHAR(255),
    requires_account_number     BOOLEAN      NOT NULL DEFAULT TRUE,
    requires_account_holder     BOOLEAN      NOT NULL DEFAULT TRUE,
    active                      BOOLEAN      NOT NULL DEFAULT TRUE,
    display_order               INTEGER      NOT NULL DEFAULT 0,
    created_at                  TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at                  TIMESTAMP    NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_exchange_receive_method UNIQUE (exchange_house_id, transfer_method_id)
);

INSERT INTO sarf.exchange_receive_methods (
    exchange_house_id, transfer_method_id, note_en, note_ar,
    requires_account_number, requires_account_holder, active, display_order
)
SELECT
    eh.id,
    tm.id,
    CASE tm.code
        WHEN 'bank_transfer' THEN 'Account number and holder name are required.'
        ELSE NULL
    END,
    CASE tm.code
        WHEN 'bank_transfer' THEN 'رقم الحساب واسم صاحبه مطلوبان.'
        ELSE NULL
    END,
    TRUE,
    TRUE,
    TRUE,
    tm.display_order
FROM sarf.exchange_houses eh
JOIN sarf.transfer_methods tm
  ON tm.code IN ('bank_transfer', 'mobile_wallet')
WHERE eh.code = 'mig'
ON CONFLICT (exchange_house_id, transfer_method_id) DO UPDATE SET
    note_en = EXCLUDED.note_en,
    note_ar = EXCLUDED.note_ar,
    requires_account_number = EXCLUDED.requires_account_number,
    requires_account_holder = EXCLUDED.requires_account_holder,
    active = EXCLUDED.active,
    display_order = EXCLUDED.display_order,
    updated_at = NOW();

-- =============================================
-- INTERNATIONAL KYC REQUIREMENTS
-- Dynamic KYC fields for international transfer.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.international_kyc_requirements (
    id                BIGSERIAL    PRIMARY KEY,
    exchange_house_id BIGINT       REFERENCES sarf.exchange_houses(id),
    provider_id       BIGINT       REFERENCES sarf.transfer_providers(id),
    field_code        VARCHAR(50)  NOT NULL,
    field_label_en    VARCHAR(100) NOT NULL,
    field_label_ar    VARCHAR(100) NOT NULL,
    field_type        VARCHAR(20)  NOT NULL CHECK (field_type IN ('TEXT', 'ATTACHMENT')),
    required          BOOLEAN      NOT NULL DEFAULT TRUE,
    allowed_mime_types TEXT[],
    display_order     INTEGER      NOT NULL DEFAULT 0,
    active            BOOLEAN      NOT NULL DEFAULT TRUE,
    created_at        TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMP    NOT NULL DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_international_kyc_requirement_specific
    ON sarf.international_kyc_requirements (exchange_house_id, provider_id, field_code)
    WHERE provider_id IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_international_kyc_requirement_generic
    ON sarf.international_kyc_requirements (exchange_house_id, field_code)
    WHERE provider_id IS NULL;

INSERT INTO sarf.international_kyc_requirements (
    exchange_house_id, provider_id, field_code, field_label_en, field_label_ar,
    field_type, required, allowed_mime_types, display_order, active
)
SELECT
    eh.id,
    NULL,
    data.field_code,
    data.field_label_en,
    data.field_label_ar,
    data.field_type,
    TRUE,
    data.allowed_mime_types,
    data.display_order,
    TRUE
FROM sarf.exchange_houses eh
JOIN (
    VALUES
        ('sender_full_name', 'Sender full name', 'الاسم الكامل للمرسل', 'TEXT', NULL::TEXT[], 1),
        ('receiver_full_name', 'Receiver full name', 'الاسم الكامل للمستلم', 'TEXT', NULL::TEXT[], 2),
        ('id_document', 'ID document', 'وثيقة الهوية', 'ATTACHMENT', ARRAY['image/jpeg', 'image/png', 'application/pdf']::TEXT[], 3)
) AS data(field_code, field_label_en, field_label_ar, field_type, allowed_mime_types, display_order)
  ON TRUE
WHERE eh.code = 'mig'
AND NOT EXISTS (
    SELECT 1
    FROM sarf.international_kyc_requirements k
    WHERE k.exchange_house_id = eh.id
      AND k.provider_id IS NULL
      AND k.field_code = data.field_code
);

-- =============================================
-- TRANSFER QUOTES
-- Shared quote table for both internal and international transfer.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.transfer_quotes (
    quote_number            VARCHAR(36)    PRIMARY KEY,
    account_number          VARCHAR(6)     NOT NULL REFERENCES sarf.users(account_number),
    service_code            VARCHAR(50)    NOT NULL REFERENCES sarf.transfer_services(code),
    status                  VARCHAR(20)    NOT NULL CHECK (status IN ('ACTIVE', 'USED', 'EXPIRED', 'CANCELLED')),
    source_currency_code    VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    target_currency_code    VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    amount_sent             NUMERIC(18, 2) NOT NULL,
    applied_rate            NUMERIC(18, 6) NOT NULL,
    gross_amount            NUMERIC(18, 2) NOT NULL,
    fee_amount              NUMERIC(18, 2) NOT NULL DEFAULT 0,
    amount_to_receive       NUMERIC(18, 2) NOT NULL,
    source_name_snapshot    VARCHAR(150),
    source_logo_url         VARCHAR(500),
    destination_name_snapshot VARCHAR(150),
    destination_logo_url    VARCHAR(500),
    payment_summary         VARCHAR(500),
    destination_summary     VARCHAR(500),
    expires_at              TIMESTAMP      NOT NULL,
    created_at              TIMESTAMP      NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMP      NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_transfer_quotes_account
    ON sarf.transfer_quotes (account_number, created_at);

CREATE TABLE IF NOT EXISTS sarf.internal_transfer_quote_details (
    quote_number        VARCHAR(36) PRIMARY KEY REFERENCES sarf.transfer_quotes(quote_number) ON DELETE CASCADE,
    route_id            BIGINT      NOT NULL REFERENCES sarf.internal_transfer_routes(id),
    merchant_id         BIGINT      NOT NULL REFERENCES sarf.merchants(id),
    merchant_account_id BIGINT      NOT NULL REFERENCES sarf.merchant_accounts(id),
    source_method_id    BIGINT      NOT NULL REFERENCES sarf.transfer_methods(id),
    target_method_id    BIGINT      NOT NULL REFERENCES sarf.transfer_methods(id)
);

CREATE TABLE IF NOT EXISTS sarf.international_transfer_quote_details (
    quote_number            VARCHAR(36) PRIMARY KEY REFERENCES sarf.transfer_quotes(quote_number) ON DELETE CASCADE,
    exchange_house_id       BIGINT      NOT NULL REFERENCES sarf.exchange_houses(id),
    provider_id             BIGINT      NOT NULL REFERENCES sarf.transfer_providers(id),
    provider_rate_id        BIGINT      NOT NULL REFERENCES sarf.exchange_provider_rates(id),
    receive_method_id       BIGINT      REFERENCES sarf.transfer_methods(id),
    provider_reference_required BOOLEAN  NOT NULL DEFAULT TRUE
);

-- =============================================
-- TRANSFER ORDERS
-- Shared order table for both internal and international transfer.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.transfer_orders (
    order_number            VARCHAR(36)    PRIMARY KEY,
    quote_number            VARCHAR(36)    REFERENCES sarf.transfer_quotes(quote_number),
    account_number          VARCHAR(6)     NOT NULL REFERENCES sarf.users(account_number),
    service_code            VARCHAR(50)    NOT NULL REFERENCES sarf.transfer_services(code),
    status                  VARCHAR(30)    NOT NULL CHECK (status IN (
                                'PENDING_PAYMENT',
                                'RECEIPT_UPLOADED',
                                'SUBMITTED',
                                'UNDER_REVIEW',
                                'MORE_INFO_REQUIRED',
                                'READY_FOR_PAYOUT',
                                'COMPLETED',
                                'REJECTED',
                                'CANCELLED',
                                'EXPIRED'
                            )),
    source_currency_code    VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    target_currency_code    VARCHAR(10)    NOT NULL REFERENCES sarf.currencies(code),
    amount_sent             NUMERIC(18, 2) NOT NULL,
    applied_rate            NUMERIC(18, 6) NOT NULL,
    gross_amount            NUMERIC(18, 2) NOT NULL,
    fee_amount              NUMERIC(18, 2) NOT NULL DEFAULT 0,
    amount_to_receive       NUMERIC(18, 2) NOT NULL,
    source_name_snapshot    VARCHAR(150),
    source_logo_url         VARCHAR(500),
    destination_name_snapshot VARCHAR(150),
    destination_logo_url    VARCHAR(500),
    payment_summary         VARCHAR(500),
    destination_summary     VARCHAR(500),
    customer_reference      VARCHAR(100),
    notes                   VARCHAR(500),
    created_at              TIMESTAMP      NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMP      NOT NULL DEFAULT NOW(),
    submitted_at            TIMESTAMP      NOT NULL DEFAULT NOW(),
    reviewed_at             TIMESTAMP,
    completed_at            TIMESTAMP,
    cancelled_at            TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_transfer_orders_status
    ON sarf.transfer_orders (status, created_at);

CREATE INDEX IF NOT EXISTS idx_transfer_orders_account
    ON sarf.transfer_orders (account_number, created_at);

CREATE TABLE IF NOT EXISTS sarf.internal_transfer_order_details (
    order_number        VARCHAR(36) PRIMARY KEY REFERENCES sarf.transfer_orders(order_number) ON DELETE CASCADE,
    route_id            BIGINT      NOT NULL REFERENCES sarf.internal_transfer_routes(id),
    merchant_id         BIGINT      NOT NULL REFERENCES sarf.merchants(id),
    merchant_account_id BIGINT      NOT NULL REFERENCES sarf.merchant_accounts(id),
    source_method_id    BIGINT      NOT NULL REFERENCES sarf.transfer_methods(id),
    target_method_id    BIGINT      NOT NULL REFERENCES sarf.transfer_methods(id)
);

CREATE TABLE IF NOT EXISTS sarf.international_transfer_order_details (
    order_number                VARCHAR(36) PRIMARY KEY REFERENCES sarf.transfer_orders(order_number) ON DELETE CASCADE,
    exchange_house_id           BIGINT      NOT NULL REFERENCES sarf.exchange_houses(id),
    provider_id                 BIGINT      NOT NULL REFERENCES sarf.transfer_providers(id),
    provider_rate_id            BIGINT      NOT NULL REFERENCES sarf.exchange_provider_rates(id),
    receive_method_id           BIGINT      REFERENCES sarf.transfer_methods(id),
    provider_reference          VARCHAR(100),
    sender_full_name            VARCHAR(150) NOT NULL,
    receiver_full_name          VARCHAR(150) NOT NULL,
    destination_account_number  VARCHAR(100) NOT NULL,
    destination_account_holder  VARCHAR(150) NOT NULL,
    kyc_data_json               JSONB
);

-- =============================================
-- ORDER ATTACHMENTS
-- File metadata for receipts, KYC docs, payout proofs, etc.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.transfer_order_attachments (
    id                BIGSERIAL    PRIMARY KEY,
    order_number      VARCHAR(36)  NOT NULL REFERENCES sarf.transfer_orders(order_number) ON DELETE CASCADE,
    attachment_type   VARCHAR(30)  NOT NULL CHECK (attachment_type IN ('RECEIPT', 'KYC_DOCUMENT', 'PAYOUT_PROOF', 'OTHER')),
    label_en          VARCHAR(100),
    label_ar          VARCHAR(100),
    file_name         VARCHAR(255) NOT NULL,
    content_type      VARCHAR(100),
    storage_key       VARCHAR(500),
    preview_url       VARCHAR(500),
    file_data         BYTEA,
    uploaded_at       TIMESTAMP    NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_transfer_order_attachments_order
    ON sarf.transfer_order_attachments (order_number, uploaded_at);

-- =============================================
-- ORDER STATUS HISTORY
-- Full audit trail for order lifecycle.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.transfer_order_status_history (
    id              BIGSERIAL   PRIMARY KEY,
    order_number    VARCHAR(36) NOT NULL REFERENCES sarf.transfer_orders(order_number) ON DELETE CASCADE,
    from_status     VARCHAR(30),
    to_status       VARCHAR(30) NOT NULL,
    actor_type      VARCHAR(30) NOT NULL CHECK (actor_type IN ('SYSTEM', 'USER', 'ADMIN', 'MERCHANT', 'EXCHANGE')),
    actor_reference VARCHAR(100),
    note            VARCHAR(500),
    created_at      TIMESTAMP   NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_transfer_order_status_history_order
    ON sarf.transfer_order_status_history (order_number, created_at);

-- =============================================
-- NOTIFICATIONS
-- Supports unread/read screens in the app.
-- =============================================
CREATE TABLE IF NOT EXISTS sarf.notifications (
    id              BIGSERIAL    PRIMARY KEY,
    account_number  VARCHAR(6)   NOT NULL REFERENCES sarf.users(account_number),
    category        VARCHAR(30)  NOT NULL CHECK (category IN ('TRANSFER', 'ACCOUNT', 'SECURITY', 'PROMOTION')),
    title_en        VARCHAR(255) NOT NULL,
    title_ar        VARCHAR(255) NOT NULL,
    content_en      VARCHAR(1000) NOT NULL,
    content_ar      VARCHAR(1000) NOT NULL,
    order_number    VARCHAR(36)  REFERENCES sarf.transfer_orders(order_number),
    is_read         BOOLEAN      NOT NULL DEFAULT FALSE,
    created_at      TIMESTAMP    NOT NULL DEFAULT NOW(),
    read_at         TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_notifications_account_read
    ON sarf.notifications (account_number, is_read, created_at);

-- =============================================
-- ACCOUNT NUMBER GENERATOR FUNCTION
-- Returns a unique 6-digit numeric string.
-- =============================================
CREATE OR REPLACE FUNCTION sarf.generate_account_number()
RETURNS VARCHAR(6) AS $$
DECLARE
    new_account VARCHAR(6);
BEGIN
    LOOP
        new_account := (100000 + FLOOR(RANDOM() * 900000)::BIGINT)::TEXT;
        EXIT WHEN NOT EXISTS (
            SELECT 1
            FROM sarf.users
            WHERE account_number = new_account
        );
    END LOOP;

    RETURN new_account;
END;
$$ LANGUAGE plpgsql;

ALTER TABLE sarf.users
    ALTER COLUMN account_number SET DEFAULT sarf.generate_account_number();
